
.reputation-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .reputation-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .reputation-panel {
    gap: 8px;
    padding: 0;
  }
}

.reputation-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  max-height: 400px;
  overflow-y: auto;
}

.reputation-item {
  padding: 16px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
}

.reputation-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.faction-name {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.reputation-badge {
  padding: 4px 12px;
  border-radius: 4px;
  font-size: 0.75rem;
  font-family: var(--font-title);
  
  &.exalted {
    background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
    color: var(--matte-gilt);
    border: 1px solid rgba(216, 200, 149, 0.35);
  }
  
  &.respected {
    background: linear-gradient(135deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.15));
    color: var(--twilight-mountain-purple);
    border: 1px solid rgba(176, 162, 209, 0.35);
  }
  
  &.friendly {
    background: linear-gradient(135deg, rgba(164, 195, 178, 0.25), rgba(164, 195, 178, 0.15));
    color: var(--bamboo-green);
    border: 1px solid rgba(164, 195, 178, 0.35);
  }
  
  &.neutral {
    background: linear-gradient(135deg, rgba(154, 184, 201, 0.25), rgba(154, 184, 201, 0.15));
    color: var(--misty-sunset-cyan);
    border: 1px solid rgba(154, 184, 201, 0.35);
  }
  
  &.cold {
    background: linear-gradient(135deg, rgba(154, 154, 184, 0.25), rgba(154, 154, 184, 0.15));
    color: #9a9ab8;
    border: 1px solid rgba(154, 154, 184, 0.35);
  }
  
  &.hostile {
    background: linear-gradient(135deg, rgba(201, 154, 154, 0.25), rgba(201, 154, 154, 0.15));
    color: #c99a9a;
    border: 1px solid rgba(201, 154, 154, 0.35);
  }
  
  &.enemy {
    background: linear-gradient(135deg, rgba(201, 154, 184, 0.25), rgba(201, 154, 184, 0.15));
    color: #c99ab8;
    border: 1px solid rgba(201, 154, 184, 0.35);
  }
}

.reputation-bar-container {
  margin-bottom: 8px;
}

.reputation-bar {
  height: 8px;
  background: rgba(154, 184, 201, 0.1);
  border-radius: 4px;
  display: flex;
  align-items: center;
  margin-bottom: 4px;
}

.reputation-bar-negative {
  height: 100%;
  background: linear-gradient(90deg, #c99ab8, rgba(201, 154, 184, 0.5));
  border-radius: 4px 0 0 4px;
  transition: width 0.3s;
}

.reputation-divider {
  width: 2px;
  height: 12px;
  background: var(--deep-mist-cyan);
  border-radius: 1px;
}

.reputation-bar-positive {
  height: 100%;
  background: linear-gradient(90deg, rgba(164, 195, 178, 0.5), var(--bamboo-green));
  border-radius: 0 4px 4px 0;
  transition: width 0.3s;
}

.reputation-value {
  text-align: center;
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  
  &.positive {
    color: var(--bamboo-green);
  }
  
  &.negative {
    color: #c99ab8;
  }
}

.reputation-scale {
  display: flex;
  justify-content: space-between;
  padding: 0 4px;
}

.scale-item {
  font-size: 0.65rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.rank-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.rank-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
}

.rank-icon {
  font-size: 1.1rem;
  width: 28px;
  text-align: center;
}

.rank-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 80px;
}

.rank-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.rank-range {
  font-size: 0.7rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.rank-desc {
  font-size: 0.75rem;
  color: var(--ink-gray);
  font-family: var(--font-title);
  margin: 0;
  flex: 1;
}

.effect-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.effect-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
}

.effect-icon {
  font-size: 1.1rem;
}

.effect-content {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.effect-title {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.effect-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}
