
.title-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .title-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .title-panel {
    gap: 8px;
    padding: 0;
  }
}

.title-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 300px;
  overflow-y: auto;
}

.title-card {
  padding: 14px;
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.12), rgba(249, 251, 252, 0.7));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
}

.title-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
}

.title-icon {
  font-size: 1rem;
  color: var(--matte-gilt);
}

.title-name {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.title-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.title-info {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.type-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
}

@media (max-width: 480px) {
  .type-grid {
    grid-template-columns: 1fr;
  }
}

.type-item {
  padding: 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
  text-align: center;
}

.type-header {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  margin-bottom: 6px;
}

.type-icon {
  font-size: 1.3rem;
}

.type-name {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.type-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
  margin: 0;
}

.effect-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.effect-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
}

.effect-icon {
  font-size: 1.1rem;
}

.effect-content {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.effect-title {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.effect-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}
