
.relations-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .relations-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .relations-panel {
    gap: 8px;
    padding: 0;
  }
}

.empty-state {
  padding: 30px 20px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border-radius: 10px;
  border: 1px solid rgba(154, 184, 201, 0.15);
}

.npc-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  max-height: 400px;
  overflow-y: auto;
}

.npc-card {
  padding: 16px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  box-shadow: 0 4px 12px rgba(90, 123, 140, 0.06);
  transition: all 0.4s ease;
}

.npc-header {
  display: flex;
  gap: 14px;
  margin-bottom: 14px;
}

.npc-avatar {
  width: 48px;
  height: 48px;
  background: linear-gradient(135deg, var(--bamboo-green), #8AAF9E);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  box-shadow: 0 4px 12px rgba(164, 195, 178, 0.25);
}

.avatar-icon {
  font-size: 1.2rem;
  color: white;
  font-family: var(--font-title);
}

.npc-info {
  flex: 1;
}

.npc-name {
  font-size: 1.05rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  margin-bottom: 6px;
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.npc-basics {
  display: flex;
  gap: 8px;
}

.npc-details {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 14px;
  padding-bottom: 14px;
  border-bottom: 1px dashed rgba(154, 184, 201, 0.2);
}

.detail-row {
  display: flex;
  gap: 12px;
  font-size: 0.85rem;
}

.detail-label {
  color: var(--misty-sunset-cyan);
  width: 36px;
  flex-shrink: 0;
}

.detail-value {
  color: var(--ink-gray);
}

.relation-section {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.relation-item {
  display: flex;
  align-items: center;
  gap: 12px;
}

.relation-label {
  width: 36px;
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  flex-shrink: 0;
}

.relation-value {
  font-size: 0.85rem;
  color: var(--bamboo-green);
  font-weight: 500;
}

.relation-bar-wrapper {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 10px;
}

.relation-number {
  width: 32px;
  text-align: right;
  font-size: 0.8rem;
  color: var(--ink-gray);
  font-weight: 500;
}

.emotion-tag {
  padding: 3px 12px;
  border-radius: 4px;
  font-size: 0.8rem;
  letter-spacing: 0.5px;
  font-family: var(--font-title);
}

.emotion-平静 {
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.2), rgba(154, 184, 201, 0.1));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.3);
}

.emotion-友好 {
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.25), rgba(164, 195, 178, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(164, 195, 178, 0.35);
}

.emotion-高兴 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.35);
}

.emotion-愤怒 {
  background: linear-gradient(135deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.emotion-悲伤 {
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.25), rgba(154, 184, 201, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.35);
}

.emotion-恐惧 {
  background: linear-gradient(135deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.emotion-厌恶 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.35);
}

.emotion-警惕 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.35);
}

.emotion-信任 {
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.25), rgba(164, 195, 178, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(164, 195, 178, 0.35);
}

.emotion-依赖 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.2), rgba(164, 195, 178, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.3);
}

.npc-traits {
  margin-top: 12px;
  padding-top: 12px;
  border-top: 1px dashed rgba(154, 184, 201, 0.2);
}

.trait-item {
  font-size: 0.85rem;
  color: var(--ink-gray);
  line-height: 1.8;
  margin-bottom: 4px;
}

.trait-label {
  color: var(--misty-sunset-cyan);
  margin-right: 6px;
}
