
.save-panel {
  height: 100%;
  display: flex;
  flex-direction: column;
}

@media (max-width: 768px) {
  .save-panel {
    min-height: 300px;
  }
}

.save-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 15px;
  
  h3 {
    margin: 0;
    font-size: 1rem;
    color: var(--deep-mist-cyan);
    font-family: var(--font-title);
    letter-spacing: 2px;
  }
  
  .save-btn {
    padding: 6px 12px;
    font-size: 0.85rem;
    
    i {
      margin-right: 5px;
    }
  }
}

@media (max-width: 768px) {
  .save-header {
    margin-bottom: 12px;
    flex-wrap: wrap;
    gap: 10px;
    
    h3 {
      font-size: 0.95rem;
      letter-spacing: 1px;
    }
    
    .save-btn {
      padding: 5px 10px;
      font-size: 0.8rem;
    }
  }
}

.save-list {
  flex: 1;
  overflow-y: auto;
}

.no-saves {
  text-align: center;
  padding: 40px 20px;
  color: var(--misty-sunset-cyan);
  
  i {
    font-size: 2rem;
    margin-bottom: 10px;
    display: block;
  }
  
  p {
    margin: 0;
    font-size: 0.9rem;
    font-family: var(--font-title);
  }
}

.save-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px;
  margin-bottom: 10px;
  background: linear-gradient(135deg, 
    rgba(249, 251, 252, 0.7),
    rgba(232, 238, 242, 0.5)
  );
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 8px;
  transition: all 0.2s;
  
  &:hover {
    border-color: rgba(216, 200, 149, 0.4);
    box-shadow: 0 2px 8px rgba(164, 195, 178, 0.1);
  }
}

.save-info {
  flex: 1;
  min-width: 0;
}

.save-name {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  margin-bottom: 4px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.save-meta {
  display: flex;
  gap: 10px;
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.save-actions {
  display: flex;
  gap: 8px;
}

.action-btn {
  width: 32px;
  height: 32px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 6px;
  color: var(--deep-mist-cyan);
  cursor: pointer;
  transition: all 0.2s;
  font-size: 0.85rem;
  
  &:hover {
    transform: translateY(-1px);
  }
  
  &.load-btn:hover {
    background: rgba(76, 175, 80, 0.2);
    border-color: rgba(76, 175, 80, 0.4);
    color: #4caf50;
  }
  
  &.overwrite-btn:hover {
    background: rgba(33, 150, 243, 0.2);
    border-color: rgba(33, 150, 243, 0.4);
    color: #2196f3;
  }
  
  &.delete-btn:hover {
    background: rgba(244, 67, 54, 0.2);
    border-color: rgba(244, 67, 54, 0.4);
    color: #f44336;
  }
}

.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  backdrop-filter: blur(5px);
}

.modal-content {
  background: linear-gradient(135deg, var(--mist-white), var(--light-cloud-gray));
  padding: 20px;
  border-radius: 12px;
  border: 1px solid rgba(216, 200, 149, 0.3);
  max-width: 300px;
  text-align: center;
  
  h4 {
    margin: 0 0 10px;
    color: var(--deep-mist-cyan);
    font-family: var(--font-title);
  }
  
  p {
    margin: 0 0 20px;
    color: var(--ink-gray);
    font-size: 0.9rem;
    font-family: var(--font-title);
  }
}

.modal-actions {
  display: flex;
  gap: 10px;
  justify-content: center;
}
