
.world-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .world-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .world-panel {
    gap: 8px;
    padding: 0;
  }
}

.location-card {
  padding: 16px;
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.15), rgba(249, 251, 252, 0.8));
  border: 1px solid rgba(216, 200, 149, 0.3);
  border-radius: 10px;
  display: flex;
  align-items: center;
  gap: 14px;
}

.location-icon {
  font-size: 1.5rem;
}

.location-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.location-name {
  font-size: 1.1rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.location-region {
  font-size: 0.85rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.region-detail {
  margin-top: 12px;
  padding: 12px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border-radius: 8px;
  border: 1px solid rgba(216, 200, 149, 0.15);
}

.detail-row {
  display: flex;
  gap: 12px;
  margin-bottom: 8px;
  font-size: 0.85rem;
}

.detail-label {
  color: var(--misty-sunset-cyan);
  min-width: 60px;
  font-family: var(--font-title);
}

.detail-value {
  color: var(--ink-gray);
  flex: 1;
  font-family: var(--font-title);
}

.danger-level {
  display: flex;
  gap: 3px;
}

.danger-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: rgba(154, 184, 201, 0.2);
  
  &.active {
    background: linear-gradient(135deg, var(--misty-sunset-cyan), var(--deep-mist-cyan));
  }
}

.danger-level.small {
  .danger-dot {
    width: 6px;
    height: 6px;
  }
}

.faction-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.faction-tag {
  padding: 3px 10px;
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.18), rgba(216, 200, 149, 0.1));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 4px;
  font-size: 0.75rem;
  color: var(--deep-mist-cyan);
  cursor: pointer;
  transition: all 0.2s;
  font-family: var(--font-title);
  
  &:hover {
    background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
    transform: translateY(-2px);
  }
}

.resource-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.resource-tag {
  padding: 3px 10px;
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.18), rgba(164, 195, 178, 0.1));
  border: 1px solid rgba(164, 195, 178, 0.25);
  border-radius: 4px;
  font-size: 0.75rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.race-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
}

@media (max-width: 480px) {
  .race-grid {
    grid-template-columns: 1fr;
  }
}

.race-card {
  padding: 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  display: flex;
  align-items: center;
  gap: 12px;
  cursor: pointer;
  transition: all 0.2s;
}

.race-icon {
  width: 40px;
  height: 40px;
  background: linear-gradient(135deg, var(--bamboo-green), #8AAF9E);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.2rem;
  color: white;
  font-family: var(--font-title);
}

.race-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.race-name {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.race-trait {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.faction-list, .region-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 300px;
  overflow-y: auto;
}

.faction-item, .region-item {
  padding: 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
}

.faction-header, .region-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 8px;
}

.faction-type-badge, .region-type-badge {
  padding: 3px 10px;
  border-radius: 4px;
  font-size: 0.7rem;
  letter-spacing: 0.5px;
  font-family: var(--font-title);
}

.type-正道 {
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.25), rgba(164, 195, 178, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(164, 195, 178, 0.35);
}

.type-魔道 {
  background: linear-gradient(135deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.type-妖族 {
  background: linear-gradient(135deg, rgba(201, 154, 184, 0.25), rgba(201, 154, 184, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(201, 154, 184, 0.35);
}

.type-中立 {
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.25), rgba(154, 184, 201, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.35);
}

.type-大陆 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.2), rgba(216, 200, 149, 0.12));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.3);
}

.type-岛屿 {
  background: linear-gradient(135deg, rgba(154, 201, 184, 0.2), rgba(154, 201, 184, 0.12));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 201, 184, 0.3);
}

.type-秘境 {
  background: linear-gradient(135deg, rgba(176, 162, 209, 0.2), rgba(176, 162, 209, 0.12));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.3);
}

.type-海域 {
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.2), rgba(154, 184, 201, 0.12));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.3);
}

.faction-name, .region-name {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.faction-meta, .region-meta {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.faction-region {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.faction-stats, .region-stats {
  display: flex;
  gap: 16px;
}

.stat-item {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.stat-label {
  font-size: 0.7rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.stat-value {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.relation-value {
  &.positive {
    color: var(--bamboo-green);
  }
  
  &.negative {
    color: #e57373;
  }
}

.region-desc {
  font-size: 0.8rem;
  color: var(--ink-gray);
  line-height: 1.6;
  font-family: var(--font-title);
}
