
.dialog-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10000;
  backdrop-filter: blur(5px);
  padding: 20px;
}

.dialog-content {
  background: linear-gradient(135deg, var(--mist-white), var(--light-cloud-gray));
  padding: 20px;
  border-radius: 12px;
  border: 1px solid rgba(216, 200, 149, 0.3);
  max-width: 320px;
  width: 100%;
  box-shadow: 0 8px 32px rgba(90, 123, 140, 0.2);
  animation: dialog-fade-in 0.2s ease-out;
}

@media (max-width: 768px) {
  .dialog-content {
    max-width: 90%;
    padding: 18px;
    border-radius: 10px;
  }
}

@media (max-width: 480px) {
  .dialog-content {
    max-width: 95%;
    padding: 15px;
    border-radius: 8px;
  }
}

@keyframes dialog-fade-in {
  from {
    opacity: 0;
    transform: scale(0.95);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

.dialog-header {
  margin-bottom: 12px;
  
  h4 {
    margin: 0;
    color: var(--deep-mist-cyan);
    font-family: var(--font-title);
    font-size: 1.1rem;
    letter-spacing: 2px;
  }
}

@media (max-width: 768px) {
  .dialog-header h4 {
    font-size: 1rem;
    letter-spacing: 1px;
  }
}

@media (max-width: 480px) {
  .dialog-header h4 {
    font-size: 0.95rem;
  }
}

.dialog-body {
  margin-bottom: 20px;
  
  p {
    margin: 0;
    color: var(--ink-gray);
    font-size: 0.9rem;
    font-family: var(--font-title);
    line-height: 1.6;
  }
}

@media (max-width: 768px) {
  .dialog-body p {
    font-size: 0.85rem;
  }
}

@media (max-width: 480px) {
  .dialog-body p {
    font-size: 0.8rem;
  }
}

.dialog-actions {
  display: flex;
  gap: 10px;
  justify-content: flex-end;
  
  .xianxia-btn {
    padding: 8px 16px;
    font-size: 0.85rem;
  }
}

@media (max-width: 768px) {
  .dialog-actions {
    gap: 8px;
    
    .xianxia-btn {
      padding: 7px 14px;
      font-size: 0.8rem;
    }
  }
}

@media (max-width: 480px) {
  .dialog-actions {
    flex-direction: column;
    gap: 6px;
    
    .xianxia-btn {
      width: 100%;
      padding: 8px 12px;
    }
  }
}
