
.protagonist-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .protagonist-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .protagonist-panel {
    gap: 8px;
    padding: 0;
  }
}

.character-header {
  display: flex;
  gap: 16px;
  align-items: center;
  padding: 20px;
  background: linear-gradient(135deg, 
    rgba(232, 238, 242, 0.95),
    rgba(249, 251, 252, 0.9)
  );
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 12px;
  box-shadow: 0 8px 32px rgba(90, 123, 140, 0.1);
  position: relative;
  overflow: hidden;
  transition: all 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

@media (max-width: 768px) {
  .character-header {
    padding: 15px;
    gap: 12px;
  }
}

@media (max-width: 480px) {
  .character-header {
    padding: 12px;
    gap: 10px;
    border-radius: 10px;
  }
}

.character-header::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(135deg, 
    rgba(154, 184, 201, 0.05),
    transparent 50%
  );
  pointer-events: none;
}

.character-header::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(216, 200, 149, 0.2), transparent);
}

.character-header:hover {
  transform: translateY(-5px);
  box-shadow: 
    0 8px 32px rgba(90, 123, 140, 0.1),
    0 0 10px rgba(164, 195, 178, 0.1);
}

.avatar-container {
  position: relative;
  flex-shrink: 0;
}

.avatar-placeholder {
  width: 64px;
  height: 64px;
  background: linear-gradient(15deg, var(--matte-gilt), rgba(216, 200, 149, 0.8));
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  z-index: 1;
  box-shadow: 0 0 20px rgba(216, 200, 149, 0.2);
}

.avatar-icon {
  font-family: var(--font-title);
  font-size: 1.6rem;
  color: white;
  letter-spacing: 0;
  font-weight: 500;
}

.avatar-ring {
  position: absolute;
  top: -4px;
  left: -4px;
  right: -4px;
  bottom: -4px;
  border: 2px solid var(--matte-gilt);
  border-radius: 50%;
  opacity: 0.4;
  animation: pulse-glow 2.5s ease-in-out infinite;
}

.character-info {
  flex: 1;
}

.character-name {
  font-size: 1.4rem;
  margin-bottom: 8px;
  font-weight: 500;
}

.character-basics {
  display: flex;
  gap: 8px;
}

.realm-display {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
}

.realm-hint {
  font-size: 0.8rem;
  color: var(--ink-gray);
  letter-spacing: 1px;
  font-family: var(--font-title);
  font-weight: 400;
}

.progress-wrapper {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.progress-label {
  font-size: 0.75rem;
  color: var(--ink-gray);
  letter-spacing: 0.5px;
  font-family: var(--font-title);
  font-weight: 400;
}

.spirit-display {
  margin-bottom: 8px;
}

.spirit-numbers {
  display: flex;
  align-items: baseline;
  gap: 4px;
  margin-bottom: 8px;
}

.spirit-current {
  font-size: 1.5rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.spirit-divider {
  color: var(--ink-gray);
  font-size: 1rem;
}

.spirit-max {
  font-size: 1rem;
  color: var(--ink-gray);
  font-family: var(--font-title);
  font-weight: 400;
}

.spirit-recovery {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 0.8rem;
  color: var(--ink-gray);
  font-family: var(--font-title);
  font-weight: 400;
}

.recovery-icon {
  color: var(--bamboo-green);
  font-size: 1rem;
}

.attributes-grid {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.attribute-item {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.attr-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.attr-name {
  font-size: 0.85rem;
  color: var(--ink-gray);
  letter-spacing: 1px;
  font-family: var(--font-title);
  font-weight: 400;
}

.attr-value {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.appearance-text {
  font-size: 0.9rem;
  color: var(--deep-mist-cyan);
  line-height: 1.8;
  padding: 12px 16px;
  background: linear-gradient(135deg, 
    rgba(249, 251, 252, 0.7),
    rgba(232, 238, 242, 0.5)
  );
  border-radius: 8px;
  border-left: 2px solid var(--bamboo-green);
  font-family: var(--font-title);
  font-weight: 400;
}

.title-list {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.title-card {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 14px;
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.12), rgba(249, 251, 252, 0.7));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s;
}

.title-icon {
  font-size: 0.9rem;
  color: var(--matte-gilt);
}

.title-name {
  font-size: 0.85rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  letter-spacing: 1px;
}

.achievement-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 200px;
  overflow-y: auto;
}

.achievement-card {
  padding: 12px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s;
}

.achievement-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.achievement-icon {
  font-size: 1rem;
}

.achievement-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  letter-spacing: 1px;
}

.achievement-desc {
  font-size: 0.8rem;
  color: var(--ink-gray);
  line-height: 1.5;
  margin: 0;
  font-family: var(--font-title);
}
