
.fate-panel {
  height: 100%;
  display: flex;
  flex-direction: column;
}

@media (max-width: 768px) {
  .fate-panel {
    min-height: 300px;
  }
}

.fate-header {
  margin-bottom: 15px;
  
  h3 {
    margin: 0;
    font-size: 1rem;
    color: var(--deep-mist-cyan);
    font-family: var(--font-title);
    letter-spacing: 2px;
  }
  
  .fate-desc {
    margin: 5px 0 0;
    font-size: 0.75rem;
    color: var(--misty-sunset-cyan);
    font-family: var(--font-title);
  }
}

@media (max-width: 768px) {
  .fate-header {
    margin-bottom: 12px;
    
    h3 {
      font-size: 0.95rem;
    }
    
    .fate-desc {
      font-size: 0.7rem;
    }
  }
}

.fate-controls {
  display: flex;
  gap: 8px;
  margin-bottom: 15px;
  
  .xianxia-btn {
    flex: 1;
    padding: 8px 12px;
    font-size: 0.8rem;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    
    .btn-icon {
      font-size: 0.9rem;
    }
    
    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }
  }
}

@media (max-width: 768px) {
  .fate-controls {
    gap: 6px;
    margin-bottom: 12px;
    
    .xianxia-btn {
      padding: 6px 10px;
      font-size: 0.75rem;
      
      .btn-icon {
        font-size: 0.85rem;
      }
    }
  }
}

.fate-tree {
  flex: 1;
  overflow-y: auto;
  padding-right: 5px;
}

.empty-fate {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: var(--misty-sunset-cyan);
  
  .empty-icon {
    font-size: 3rem;
    margin-bottom: 15px;
    opacity: 0.5;
  }
  
  p {
    margin: 0;
    font-family: var(--font-title);
    
    &.empty-hint {
      font-size: 0.8rem;
      margin-top: 8px;
      opacity: 0.7;
    }
  }
}

.children-container {
  position: relative;
  margin-left: 20px;
  padding-left: 20px;
}

.branch-line {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 50%;
  width: 2px;
  background: linear-gradient(to bottom, rgba(216, 200, 149, 0.4), rgba(216, 200, 149, 0.1));
}

.children-nodes {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
