
.achievement-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .achievement-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .achievement-panel {
    gap: 8px;
    padding: 0;
  }
}

.achievement-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  max-height: 400px;
  overflow-y: auto;
}

.achievement-card {
  padding: 16px;
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.12), rgba(249, 251, 252, 0.7));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
}

.achievement-header {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.achievement-icon {
  font-size: 1.2rem;
}

.achievement-name {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.achievement-content {
  padding-left: 32px;
}

.achievement-desc {
  font-size: 0.85rem;
  color: var(--ink-gray);
  line-height: 1.6;
  margin: 0 0 10px 0;
  font-family: var(--font-title);
}

.achievement-meta {
  display: flex;
  gap: 20px;
}

.meta-item {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.meta-label {
  font-size: 0.7rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.meta-value {
  font-size: 0.8rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  
  &.reward {
    color: var(--matte-gilt);
  }
}

.type-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
}

@media (max-width: 768px) {
  .type-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 480px) {
  .type-grid {
    grid-template-columns: 1fr;
  }
}

.type-item {
  padding: 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
  text-align: center;
}

.type-header {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  margin-bottom: 6px;
}

.type-icon {
  font-size: 1.3rem;
}

.type-name {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.type-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
  margin: 0;
}

.reward-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.reward-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
}

.reward-icon {
  font-size: 1.1rem;
}

.reward-content {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.reward-title {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.reward-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}
