
.game-container {
  width: 100%;
  aspect-ratio: 4 / 3;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

@media (max-width: 768px) {
  .game-container {
    aspect-ratio: 3 / 4;
    min-height: 100vh;
  }
}

@media (max-width: 480px) {
  .game-container {
    aspect-ratio: 9 / 16;
    min-height: 100vh;
  }
}

.loading-screen {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, var(--mist-white), var(--light-cloud-gray));
}

.loading-content {
  text-align: center;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.loading-spinner {
  width: 40px;
  height: 40px;
  border: 3px solid rgba(216, 200, 149, 0.3);
  border-top-color: var(--deep-mist-cyan);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 0 auto 15px;
}

@media (max-width: 768px) {
  .loading-spinner {
    width: 36px;
    height: 36px;
    border-width: 2px;
  }
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}
