
.fate-node-item {
  position: relative;
  margin-bottom: 8px;

  &.current {
    .node-content {
      background: linear-gradient(135deg, 
        rgba(216, 200, 149, 0.25),
        rgba(232, 238, 242, 0.6)
      );
      border-color: rgba(216, 200, 149, 0.5);
      box-shadow: 0 0 15px rgba(216, 200, 149, 0.2);
    }

    .node-icon {
      color: var(--deep-mist-cyan);
    }
  }
}

@media (max-width: 768px) {
  .fate-node-item {
    margin-bottom: 6px;
  }
}

@media (max-width: 480px) {
  .fate-node-item {
    margin-bottom: 4px;
  }
}

.node-content {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  background: linear-gradient(135deg, 
    rgba(249, 251, 252, 0.7),
    rgba(232, 238, 242, 0.5)
  );
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94);

  &:hover {
    background: linear-gradient(135deg, 
      rgba(216, 200, 149, 0.15),
      rgba(232, 238, 242, 0.55)
    );
    border-color: rgba(216, 200, 149, 0.35);
    transform: translateX(3px);
  }
}

@media (max-width: 768px) {
  .node-content {
    padding: 8px 10px;
    gap: 8px;
    
    &:active {
      transform: scale(0.98);
    }
  }
}

@media (max-width: 480px) {
  .node-content {
    padding: 6px 8px;
    gap: 6px;
    border-radius: 6px;
  }
}

.node-icon {
  font-size: 1.2rem;
  opacity: 0.8;
}

@media (max-width: 768px) {
  .node-icon {
    font-size: 1rem;
  }
}

@media (max-width: 480px) {
  .node-icon {
    font-size: 0.9rem;
  }
}

.node-info {
  flex: 1;
  min-width: 0;
}

.node-title {
  font-size: 0.85rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

@media (max-width: 768px) {
  .node-title {
    font-size: 0.8rem;
  }
}

@media (max-width: 480px) {
  .node-title {
    font-size: 0.75rem;
  }
}

.node-meta {
  display: flex;
  gap: 8px;
  margin-top: 2px;
  font-size: 0.7rem;
  color: var(--misty-sunset-cyan);
}

@media (max-width: 768px) {
  .node-meta {
    gap: 6px;
    font-size: 0.65rem;
  }
}

@media (max-width: 480px) {
  .node-meta {
    gap: 4px;
    font-size: 0.6rem;
  }
}

.node-round {
  padding: 1px 4px;
  background: rgba(216, 200, 149, 0.15);
  border-radius: 3px;
}

.node-time {
  opacity: 0.8;
}

.node-actions {
  position: absolute;
  right: 8px;
  top: 50%;
  transform: translateY(-50%);
  opacity: 0;
  transition: opacity 0.2s;

  .fate-node-item:hover & {
    opacity: 1;
  }
}

@media (max-width: 768px) {
  .node-actions {
    opacity: 1;
    right: 6px;
  }
}

.node-action-btn {
  width: 22px;
  height: 22px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 4px;
  color: var(--misty-sunset-cyan);
  cursor: pointer;
  transition: all 0.2s;
  font-size: 0.65rem;

  &:hover {
    background: rgba(244, 67, 54, 0.2);
    border-color: rgba(244, 67, 54, 0.4);
    color: #f44336;
  }
}

@media (max-width: 768px) {
  .node-action-btn {
    width: 20px;
    height: 20px;
    font-size: 0.6rem;
  }
}

.node-children {
  margin-left: 15px;
  padding-left: 15px;
  position: relative;
  margin-top: 8px;
}

@media (max-width: 768px) {
  .node-children {
    margin-left: 12px;
    padding-left: 12px;
    margin-top: 6px;
  }
}

@media (max-width: 480px) {
  .node-children {
    margin-left: 10px;
    padding-left: 10px;
    margin-top: 4px;
  }
}

.branch-connector {
  position: absolute;
  left: 0;
  top: 0;
  bottom: 50%;
  width: 2px;
  background: linear-gradient(to bottom, rgba(216, 200, 149, 0.4), rgba(216, 200, 149, 0.1));
}

.children-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

@media (max-width: 768px) {
  .children-list {
    gap: 4px;
  }
}
