  min-width: 110px;
  letter-spacing: 2px;
  font-family: var(--font-title);
  font-weight: 400;

  &:hover {
    background: linear-gradient(135deg, 
      rgba(154, 184, 201, 0.18),
      rgba(232, 238, 242, 0.7)
    );
    border-color: rgba(216, 200, 149, 0.4);
    transform: translateY(-5px);
    box-shadow: 0 0 10px rgba(164, 195, 178, 0.1);
  }

  &.selected {
    background: linear-gradient(135deg, 
      rgba(216, 200, 149, 0.22),
      rgba(216, 200, 149, 0.15)
    );
    border-color: rgba(216, 200, 149, 0.55);
    color: var(--deep-mist-cyan);
    box-shadow: 0 0 15px rgba(216, 200, 149, 0.15);
  }
}

.realm-group {
  margin-bottom: 8px;

  .realm-label {
    color: var(--misty-sunset-cyan);
    font-size: clamp(0.7rem, 2vw, 0.8rem);
    margin-bottom: 4px;
    letter-spacing: 1px;
    font-family: var(--font-title);
    font-weight: 400;
  }

  .realm-buttons {
    display: flex;
    flex-wrap: wrap;
    gap: 6px;
  }
}

.technique-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 12px;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
}

.technique-card {
  display: flex;
  flex-direction: column;
  align-items: center;
