      rgba(232, 238, 242, 0.6)
    );
    border-color: rgba(216, 200, 149, 0.5);
  }

  .tech-name {
    font-size: clamp(0.95rem, 2.5vw, 1.05rem);
    font-weight: 500;
    color: var(--deep-mist-cyan);
    letter-spacing: 2px;
  }

  .tech-desc {
    font-size: clamp(0.75rem, 2vw, 0.8rem);
    color: var(--misty-sunset-cyan);
    font-weight: 400;
  }
}

.tech-grade {
  font-size: clamp(0.65rem, 1.8vw, 0.7rem);
  padding: 2px 10px;
  border-radius: 3px;
  letter-spacing: 1px;
  font-family: var(--font-title);
  font-weight: 400;
}

.grade-天阶 {
  background: linear-gradient(15deg, rgba(216, 200, 149, 0.3), rgba(216, 200, 149, 0.2));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.4);
}

.grade-地阶 {
  background: linear-gradient(15deg, rgba(154, 184, 201, 0.25), rgba(154, 184, 201, 0.18));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.35);
}

.grade-玄阶 {
  background: linear-gradient(15deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.18));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.location-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 12px;

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
}

.location-card {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  padding: 18px;
  background: linear-gradient(135deg, 
    rgba(232, 238, 242, 0.95),
    rgba(249, 251, 252, 0.9)
  );
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  font-family: var(--font-title);
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(216, 200, 149, 0.2), transparent);
  }

  &:hover {
    background: linear-gradient(135deg, 
      rgba(154, 184, 201, 0.15),
      rgba(232, 238, 242, 0.6)
    );
    border-color: rgba(216, 200, 149, 0.35);
    transform: translateY(-5px);
    box-shadow: 0 0 10px rgba(164, 195, 178, 0.1);
  }

  &.selected {
    background: linear-gradient(135deg, 
      rgba(216, 200, 149, 0.2),
      rgba(232, 238, 242, 0.6)
    );
