  }

  .loc-desc {
    font-size: clamp(0.75rem, 2vw, 0.8rem);
    color: var(--ink-gray);
    font-weight: 400;
  }
}

.welcome-actions {
  display: flex;
  flex-direction: column;
  gap: 15px;
  align-items: center;
}

.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  backdrop-filter: blur(5px);
}

.modal-content {
  background: linear-gradient(135deg, var(--mist-white), var(--light-cloud-gray));
  padding: 25px 30px;
  border-radius: 12px;
  border: 1px solid rgba(216, 200, 149, 0.3);
  max-width: 350px;
  width: 90%;
  max-height: 70vh;
  overflow-y: auto;
}

.load-modal {
  text-align: center;
}

.modal-title {
  margin: 0 0 8px;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  font-size: 1.3rem;
  letter-spacing: 3px;
}

.modal-desc {
  margin: 0 0 20px;
  color: var(--misty-sunset-cyan);
  font-size: 0.85rem;
  font-family: var(--font-title);
}

.no-saves {
  padding: 30px 20px;
  color: var(--misty-sunset-cyan);
  
  i {
    font-size: 2rem;
    margin-bottom: 10px;
    display: block;
    opacity: 0.6;
  }
  
  p {
    margin: 0;
    font-size: 0.9rem;
    font-family: var(--font-title);
  }
}

.save-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 20px;
}

.save-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 15px;
  background: linear-gradient(135deg, 
    rgba(249, 251, 252, 0.8),
    rgba(232, 238, 242, 0.6)
  );
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 8px;
  transition: all 0.2s;
  text-align: left;
  
  &:hover {
    border-color: rgba(216, 200, 149, 0.4);
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(164, 195, 178, 0.15);
  }
}

.save-info {
  flex: 1;
  cursor: pointer;
  
  &:hover .save-name {
    color: var(--deep-mist-cyan);
  }
}

.save-name {
  font-size: 0.95rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  margin-bottom: 4px;
}

.save-meta {
  display: flex;
  gap: 10px;
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.close-btn {
  margin-top: 10px;
}

.delete-save-btn {
  width: 28px;
  height: 28px;
  padding: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 6px;
  color: var(--misty-sunset-cyan);
  cursor: pointer;
  transition: all 0.2s;
  font-size: 0.75rem;
  
  &:hover {
    background: rgba(244, 67, 54, 0.2);
    border-color: rgba(244, 67, 54, 0.4);
    color: #f44336;
    transform: translateY(-1px);
  }
}
