
.spell-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .spell-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .spell-panel {
    gap: 8px;
    padding: 0;
  }
}

.empty-state {
  padding: 30px 20px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border-radius: 10px;
  border: 1px solid rgba(154, 184, 201, 0.15);
}

.spell-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  max-height: 400px;
  overflow-y: auto;
}

.spell-card {
  padding: 16px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  box-shadow: 0 4px 12px rgba(90, 123, 140, 0.06);
  transition: all 0.4s ease;
}

.spell-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
}

.spell-name {
  font-size: 1rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.spell-badges {
  display: flex;
  gap: 8px;
}

.spell-type-badge {
  padding: 3px 10px;
  border-radius: 4px;
  font-size: 0.7rem;
  letter-spacing: 0.5px;
  font-family: var(--font-title);
}

.type-攻击 {
  background: linear-gradient(135deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.type-防御 {
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.25), rgba(154, 184, 201, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.35);
}

.type-辅助 {
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.25), rgba(164, 195, 178, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(164, 195, 178, 0.35);
}

.type-控制 {
  background: linear-gradient(135deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.type-特殊 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.35);
}

.spell-grade {
  padding: 3px 10px;
  border-radius: 4px;
  font-size: 0.7rem;
  letter-spacing: 0.5px;
  font-family: var(--font-title);
}

.grade-凡阶 {
  background: linear-gradient(135deg, rgba(232, 238, 242, 0.8), rgba(209, 216, 224, 0.6));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.25);
}

.grade-灵阶 {
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.25), rgba(164, 195, 178, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(164, 195, 178, 0.35);
}

.grade-玄阶 {
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.25), rgba(154, 184, 201, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.35);
}

.grade-地阶 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.35);
}

.grade-天阶 {
  background: linear-gradient(135deg, rgba(176, 162, 209, 0.25), rgba(176, 162, 209, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.grade-仙阶 {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.35), rgba(216, 200, 149, 0.2));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.5);
}

.spell-desc {
  font-size: 0.85rem;
  color: var(--ink-gray);
  line-height: 1.8;
  margin-bottom: 10px;
}

.spell-effect {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 10px 12px;
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.1), rgba(154, 184, 201, 0.05));
  border-radius: 6px;
  margin-bottom: 12px;
  border: 1px solid rgba(154, 184, 201, 0.12);
}

.effect-icon {
  color: var(--bamboo-green);
  font-size: 0.8rem;
  flex-shrink: 0;
}

.effect-text {
  font-size: 0.8rem;
  color: var(--ink-gray);
  line-height: 1.5;
}

.spell-stats {
  display: flex;
  gap: 20px;
  padding-top: 12px;
  border-top: 1px dashed rgba(154, 184, 201, 0.2);
}

.stat-item {
  display: flex;
  align-items: center;
  gap: 8px;
}

.stat-icon {
  font-size: 1rem;
}

.stat-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.stat-label {
  font-size: 0.7rem;
  color: var(--misty-sunset-cyan);
}

.stat-value {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
}
