
.spirit-beast-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .spirit-beast-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .spirit-beast-panel {
    gap: 8px;
    padding: 0;
  }
}

.beast-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
  max-height: 400px;
  overflow-y: auto;
}

.beast-card {
  padding: 16px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
}

.beast-header {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
}

.beast-icon {
  width: 44px;
  height: 44px;
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.3), rgba(164, 195, 178, 0.15));
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.3rem;
}

.beast-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
  flex: 1;
}

.beast-name {
  font-size: 1rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.beast-type {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.beast-status {
  padding: 4px 10px;
  border-radius: 4px;
  font-size: 0.7rem;
  font-family: var(--font-title);
  
  &.status-正常 {
    background: linear-gradient(135deg, rgba(164, 195, 178, 0.25), rgba(164, 195, 178, 0.15));
    color: var(--bamboo-green);
    border: 1px solid rgba(164, 195, 178, 0.35);
  }
  
  &.status-战斗 {
    background: linear-gradient(135deg, rgba(201, 154, 184, 0.25), rgba(201, 154, 184, 0.15));
    color: #c972b8;
    border: 1px solid rgba(201, 154, 184, 0.35);
  }
  
  &.status-休息 {
    background: linear-gradient(135deg, rgba(154, 184, 201, 0.25), rgba(154, 184, 201, 0.15));
    color: var(--misty-sunset-cyan);
    border: 1px solid rgba(154, 184, 201, 0.35);
  }
  
  &.status-受伤 {
    background: linear-gradient(135deg, rgba(201, 154, 154, 0.25), rgba(201, 154, 154, 0.15));
    color: #c99a9a;
    border: 1px solid rgba(201, 154, 154, 0.35);
  }
}

.beast-stats {
  display: flex;
  flex-direction: column;
  gap: 10px;
  margin-bottom: 12px;
}

.stat-item {
  display: flex;
  align-items: center;
  gap: 10px;
}

.stat-label {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  min-width: 50px;
  font-family: var(--font-title);
}

.star-rating {
  display: flex;
  gap: 2px;
}

.star {
  font-size: 0.7rem;
  color: rgba(216, 200, 149, 0.2);
  
  &.active {
    color: var(--matte-gilt);
  }
}

.loyalty-bar {
  flex: 1;
  height: 6px;
  background: rgba(154, 184, 201, 0.15);
  border-radius: 3px;
  overflow: hidden;
}

.loyalty-fill {
  height: 100%;
  background: linear-gradient(90deg, var(--bamboo-green), #8AAF9E);
  border-radius: 3px;
  transition: width 0.3s;
}

.stat-value {
  font-size: 0.8rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.beast-contract {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}

.contract-label {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.contract-type {
  padding: 3px 10px;
  border-radius: 4px;
  font-size: 0.75rem;
  font-family: var(--font-title);
  
  &.type-master {
    background: linear-gradient(135deg, rgba(216, 200, 149, 0.2), rgba(216, 200, 149, 0.12));
    color: var(--matte-gilt);
    border: 1px solid rgba(216, 200, 149, 0.3);
  }
  
  &.type-equal {
    background: linear-gradient(135deg, rgba(164, 195, 178, 0.2), rgba(164, 195, 178, 0.12));
    color: var(--bamboo-green);
    border: 1px solid rgba(164, 195, 178, 0.3);
  }
  
  &.type-blood {
    background: linear-gradient(135deg, rgba(201, 154, 184, 0.2), rgba(201, 154, 184, 0.12));
    color: #c972b8;
    border: 1px solid rgba(201, 154, 184, 0.3);
  }
  
  &.type-soul {
    background: linear-gradient(135deg, rgba(176, 162, 209, 0.2), rgba(176, 162, 209, 0.12));
    color: var(--twilight-mountain-purple);
    border: 1px solid rgba(176, 162, 209, 0.3);
  }
}

.beast-skills {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}

.skills-label {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.skills-list {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
}

.skill-tag {
  padding: 2px 8px;
  background: linear-gradient(135deg, rgba(154, 184, 201, 0.18), rgba(154, 184, 201, 0.1));
  border: 1px solid rgba(154, 184, 201, 0.25);
  border-radius: 4px;
  font-size: 0.7rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.contract-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
}

@media (max-width: 480px) {
  .contract-grid {
    grid-template-columns: 1fr;
  }
}

.contract-item {
  padding: 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
}

.contract-header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 8px;
}

.contract-icon {
  font-size: 1.1rem;
}

.contract-name {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.contract-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
  margin: 0;
}

.status-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.status-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
}

.status-icon {
  font-size: 1rem;
  
  &.status-normal {
    color: var(--bamboo-green);
  }
  
  &.status-battle {
    color: #c972b8;
  }
  
  &.status-rest {
    color: var(--misty-sunset-cyan);
  }
  
  &.status-injured {
    color: #c99a9a;
  }
}

.status-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  min-width: 40px;
}

.status-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}
