
.quest-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .quest-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .quest-panel {
    gap: 8px;
    padding: 0;
  }
}

.panel-section {
  background: linear-gradient(135deg, 
    rgba(232, 238, 242, 0.95),
    rgba(249, 251, 252, 0.9)
  );
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  padding: 16px;
  margin-bottom: 12px;
  backdrop-filter: blur(15px);
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(135deg, 
      rgba(154, 184, 201, 0.05),
      transparent 50%
    );
    pointer-events: none;
  }

  &::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(216, 200, 149, 0.2), transparent);
  }
}

.section-title {
  font-family: var(--font-title);
  color: var(--deep-mist-cyan);
  font-size: 0.95rem;
  margin-bottom: 14px;
  padding-bottom: 8px;
  letter-spacing: 3px;
  font-weight: 500;
  position: relative;
  display: flex;
  align-items: center;
  gap: 8px;

  &::before {
    content: '◇';
    color: var(--matte-gilt);
    font-size: 0.65rem;
  }

  &::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 50px;
    height: 1px;
    background: linear-gradient(90deg, var(--matte-gilt), transparent);
    opacity: 0.5;
  }
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 30px 20px;
  background: linear-gradient(135deg, 
    rgba(249, 251, 252, 0.6),
    rgba(232, 238, 242, 0.4)
  );
  border-radius: 8px;
  border: 1px solid rgba(216, 200, 149, 0.15);
  text-align: center;
  position: relative;
  overflow: hidden;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 1px;
    background: linear-gradient(90deg, transparent, rgba(216, 200, 149, 0.2), transparent);
  }
}

.empty-state-icon {
  font-size: 2rem;
  margin-bottom: 12px;
  opacity: 0.5;
}

.empty-state-text {
  font-size: 0.95rem;
  letter-spacing: 1px;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
  font-weight: 400;
}

.empty-state-hint {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  margin-top: 8px;
  font-family: var(--font-title);
  font-weight: 400;
}

.quest-card {
  padding: 14px 16px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  box-shadow: 0 4px 12px rgba(90, 123, 140, 0.06);
  transition: all 0.4s ease;
}

.quest-card.main-quest {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.08), rgba(249, 251, 252, 0.6));
  border-color: rgba(216, 200, 149, 0.35);
  box-shadow: 0 4px 16px rgba(216, 200, 149, 0.1);
}

.quest-header {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 10px;
}

.quest-type-badge {
  padding: 3px 10px;
  border-radius: 4px;
  font-size: 0.7rem;
  letter-spacing: 0.5px;
  flex-shrink: 0;
  font-family: var(--font-title);
}

.quest-type-badge.main {
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.25), rgba(216, 200, 149, 0.15));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.4);
}

.quest-type-badge.side {
  background: linear-gradient(135deg, rgba(164, 195, 178, 0.2), rgba(164, 195, 178, 0.1));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(164, 195, 178, 0.35);
}

.quest-title {
  font-size: 0.9rem;
  color: var(--deep-mist-cyan);
  letter-spacing: 1px;
  font-family: var(--font-title);
}

.quest-progress {
  display: flex;
  align-items: center;
  gap: 12px;
}

.progress-bar-container {
  flex: 1;
  height: 6px;
  background: rgba(154, 184, 201, 0.12);
  border-radius: 10px;
  overflow: hidden;
}

.progress-bar-fill {
  height: 100%;
  border-radius: 10px;
  transition: width 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

.progress-gold {
  background: linear-gradient(15deg, rgba(196, 176, 122, 0.9), var(--matte-gilt), rgba(229, 216, 168, 0.9));
}

.progress-hint {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  white-space: nowrap;
}

.quest-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  max-height: 200px;
  overflow-y: auto;
}

.quest-list.completed {
  opacity: 0.7;
}

.quest-card.completed {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
}

.quest-complete-icon {
  color: var(--bamboo-green);
  font-size: 0.9rem;
}

.quest-card.completed .quest-title {
  color: var(--misty-sunset-cyan);
  text-decoration: line-through;
  font-size: 0.85rem;
}
