
.tab-nav {
  display: flex;
  flex-wrap: wrap;
  gap: 5px;
  padding: 10px;
  border-bottom: 1px solid rgba(154, 184, 201, 0.15);
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.3), rgba(232, 238, 242, 0.2));
}

@media (max-width: 768px) {
  .tab-nav {
    padding: 8px;
    gap: 4px;
  }
}

@media (max-width: 480px) {
  .tab-nav {
    padding: 6px;
    gap: 3px;
  }
}

.tab-btn {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 8px 12px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.5), rgba(232, 238, 242, 0.3));
  border: 1px solid transparent;
  border-radius: 6px;
  color: var(--ink-gray);
  cursor: pointer;
  transition: all 0.4s ease;
  font-size: 0.85rem;
  font-family: var(--font-title);

  &:hover {
    background: linear-gradient(135deg, rgba(216, 200, 149, 0.12), rgba(232, 238, 242, 0.4));
    color: var(--deep-mist-cyan);
    border-color: rgba(216, 200, 149, 0.2);
  }

  &.active {
    background: linear-gradient(135deg, rgba(216, 200, 149, 0.18), rgba(216, 200, 149, 0.1));
    border-color: rgba(216, 200, 149, 0.35);
    color: var(--deep-mist-cyan);
    box-shadow: 0 2px 8px rgba(216, 200, 149, 0.1);
  }

  .tab-icon {
    font-size: 1rem;
  }
}

@media (max-width: 768px) {
  .tab-btn {
    padding: 6px 10px;
    font-size: 0.8rem;
    
    .tab-icon {
      font-size: 0.9rem;
    }
  }
}

@media (max-width: 480px) {
  .tab-btn {
    padding: 5px 8px;
    font-size: 0.75rem;
    flex: 1;
    justify-content: center;
    min-width: calc(25% - 6px);
    
    .tab-icon {
      font-size: 0.85rem;
    }
    
    .tab-label {
      font-size: 0.7rem;
    }
  }
}
