
.alchemy-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .alchemy-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .alchemy-panel {
    gap: 8px;
    padding: 0;
  }
}

.skill-card {
  padding: 20px;
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.12), rgba(249, 251, 252, 0.8));
  border: 1px solid rgba(216, 200, 149, 0.25);
  border-radius: 10px;
}

.skill-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 16px;
}

.skill-icon {
  width: 56px;
  height: 56px;
  background: linear-gradient(135deg, var(--matte-gilt), rgba(216, 200, 149, 0.8));
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.5rem;
  color: white;
  font-family: var(--font-title);
  box-shadow: 0 4px 16px rgba(216, 200, 149, 0.25);
}

.skill-info {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.skill-name {
  font-size: 1.1rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.skill-rank {
  font-size: 0.85rem;
  color: var(--matte-gilt);
  font-family: var(--font-title);
}

.skill-progress {
  margin-bottom: 12px;
}

.progress-header {
  display: flex;
  justify-content: space-between;
  margin-bottom: 8px;
}

.progress-label {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.progress-value {
  font-size: 0.8rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.skill-desc {
  p {
    font-size: 0.85rem;
    color: var(--ink-gray);
    line-height: 1.8;
    margin-bottom: 4px;
    font-family: var(--font-title);
  }
  
  .rank-info {
    color: var(--matte-gilt);
    font-weight: 500;
  }
}

.recipe-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 300px;
  overflow-y: auto;
}

.recipe-card {
  padding: 14px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.7), rgba(232, 238, 242, 0.5));
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.2s;
}

.recipe-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

.recipe-name {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 2px;
  font-family: var(--font-title);
}

.recipe-type {
  padding: 3px 10px;
  background: linear-gradient(135deg, rgba(216, 200, 149, 0.2), rgba(216, 200, 149, 0.12));
  border: 1px solid rgba(216, 200, 149, 0.3);
  border-radius: 4px;
  font-size: 0.7rem;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.recipe-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.recipe-info {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}

.quality-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 8px;
}

@media (max-width: 768px) {
  .quality-grid {
    grid-template-columns: repeat(3, 1fr);
  }
}

@media (max-width: 480px) {
  .quality-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

.quality-item {
  padding: 12px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
  text-align: center;
}

.quality-header {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  margin-bottom: 6px;
}

.quality-icon {
  font-size: 1.2rem;
  color: var(--matte-gilt);
}

.quality-name {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.quality-desc {
  font-size: 0.7rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
  margin: 0;
}

.info-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.info-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px;
  background: linear-gradient(135deg, rgba(249, 251, 252, 0.6), rgba(232, 238, 242, 0.4));
  border: 1px solid rgba(216, 200, 149, 0.15);
  border-radius: 8px;
}

.info-icon {
  font-size: 1.2rem;
}

.info-content {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.info-title {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.info-desc {
  font-size: 0.75rem;
  color: var(--misty-sunset-cyan);
  font-family: var(--font-title);
}
