
.inventory-panel {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding: 4px;
}

@media (max-width: 768px) {
  .inventory-panel {
    gap: 10px;
    padding: 2px;
  }
}

@media (max-width: 480px) {
  .inventory-panel {
    gap: 8px;
    padding: 0;
  }
}

.spirit-stones-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 10px;
}

@media (max-width: 480px) {
  .spirit-stones-grid {
    grid-template-columns: 1fr;
    gap: 8px;
  }
}

.stone-card {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 16px;
  background: linear-gradient(135deg, 
    rgba(249, 251, 252, 0.8),
    rgba(232, 238, 242, 0.6)
  );
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  position: relative;
  overflow: hidden;
  transition: all 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

.stone-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(216, 200, 149, 0.2), transparent);
}

.stone-card:hover {
  transform: translateY(-5px);
  box-shadow: 
    0 8px 32px rgba(90, 123, 140, 0.1),
    0 0 10px rgba(164, 195, 178, 0.1);
}

.stone-icon-wrapper {
  width: 40px;
  height: 40px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  border: 2px solid transparent;
}

.stone-symbol {
  font-size: 1.2rem;
}

.stone-下品 {
  background: linear-gradient(15deg, rgba(232, 238, 242, 0.9), rgba(232, 238, 242, 0.6));
  color: var(--ink-gray);
  border-color: rgba(154, 184, 201, 0.3);
}

.stone-中品 {
  background: linear-gradient(15deg, rgba(154, 184, 201, 0.3), rgba(154, 184, 201, 0.18));
  color: var(--misty-sunset-cyan);
  border-color: rgba(154, 184, 201, 0.4);
}

.stone-上品 {
  background: linear-gradient(15deg, rgba(216, 200, 149, 0.3), rgba(216, 200, 149, 0.18));
  color: var(--matte-gilt);
  border-color: rgba(216, 200, 149, 0.4);
}

.stone-极品 {
  background: linear-gradient(15deg, rgba(176, 162, 209, 0.3), rgba(176, 162, 209, 0.18));
  color: var(--twilight-mountain-purple);
  border-color: rgba(176, 162, 209, 0.4);
}

.stone-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.stone-grade {
  font-size: 0.75rem;
  color: var(--ink-gray);
  letter-spacing: 1px;
  font-family: var(--font-title);
  font-weight: 400;
}

.stone-amount {
  font-size: 1.1rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  font-family: var(--font-title);
}

.empty-state {
  padding: 30px 20px;
}

.empty-state-hint {
  font-size: 0.8rem;
  color: var(--misty-sunset-cyan);
  margin-top: 6px;
  font-family: var(--font-title);
  font-weight: 400;
}

.items-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 300px;
  overflow-y: auto;
  padding-right: 4px;
}

.item-card {
  padding: 14px 16px;
  background: linear-gradient(135deg, 
    rgba(249, 251, 252, 0.8),
    rgba(232, 238, 242, 0.6)
  );
  border: 1px solid rgba(216, 200, 149, 0.2);
  border-radius: 10px;
  position: relative;
  overflow: hidden;
  transition: all 0.2s cubic-bezier(0.25, 0.46, 0.45, 0.94);
}

.item-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, rgba(216, 200, 149, 0.2), transparent);
}

.item-card:hover {
  transform: translateY(-5px);
  box-shadow: 
    0 8px 32px rgba(90, 123, 140, 0.1),
    0 0 10px rgba(164, 195, 178, 0.1);
}

.item-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

.item-name {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--deep-mist-cyan);
  letter-spacing: 1px;
  font-family: var(--font-title);
}

.item-grade {
  font-size: 0.7rem;
  padding: 3px 10px;
  border-radius: 4px;
  letter-spacing: 0.5px;
  font-family: var(--font-title);
  font-weight: 400;
}

.grade-凡阶 {
  background: linear-gradient(15deg, rgba(232, 238, 242, 0.9), rgba(232, 238, 242, 0.6));
  color: var(--ink-gray);
  border: 1px solid rgba(154, 184, 201, 0.3);
}

.grade-灵阶 {
  background: linear-gradient(15deg, rgba(164, 195, 178, 0.28), rgba(164, 195, 178, 0.18));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(164, 195, 178, 0.35);
}

.grade-玄阶 {
  background: linear-gradient(15deg, rgba(154, 184, 201, 0.28), rgba(154, 184, 201, 0.18));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(154, 184, 201, 0.35);
}

.grade-地阶 {
  background: linear-gradient(15deg, rgba(216, 200, 149, 0.28), rgba(216, 200, 149, 0.18));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.35);
}

.grade-天阶 {
  background: linear-gradient(15deg, rgba(176, 162, 209, 0.28), rgba(176, 162, 209, 0.18));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(176, 162, 209, 0.35);
}

.grade-仙阶 {
  background: linear-gradient(15deg, rgba(216, 200, 149, 0.35), rgba(216, 200, 149, 0.25));
  color: var(--deep-mist-cyan);
  border: 1px solid rgba(216, 200, 149, 0.5);
}

.item-meta {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
}

.item-type {
  font-size: 0.75rem;
  color: var(--ink-gray);
  letter-spacing: 0.5px;
  font-family: var(--font-title);
  font-weight: 400;
}

.item-quantity {
  font-size: 0.8rem;
  color: var(--bamboo-green);
  font-weight: 400;
  font-family: var(--font-title);
}

.item-desc {
  font-size: 0.8rem;
  color: var(--deep-mist-cyan);
  line-height: 1.8;
  padding-top: 8px;
  border-top: 1px dashed rgba(154, 184, 201, 0.2);
  font-family: var(--font-title);
  font-weight: 400;
}
